// mm/src/api/uploadDocuments.js
import axios from 'axios';
import { withAuthRetry } from './refresh';

const DEFAULT_API_BASE = 'https://manuscriptmagic.fowkes.xyz/services';
const API_BASE = process.env.REACT_APP_API_BASE_URL || DEFAULT_API_BASE;

const ACCESS_KEY = 'mm_accessToken';

function getAccessToken() {
  return localStorage.getItem(ACCESS_KEY) || '';
}

/**
 * Upload a single document file to the backend.
 *
 * Backend endpoint: uploadDocument.php
 * Expects multipart/form-data with:
 *   - document: File (binary)
 * Uses:
 *   - Authorization: Bearer <accessToken>
 *
 * Returns a normalized shape:
 *   Success:
 *     { success: true, data: <backendResponse>, status: <httpStatus> }
 *   Failure:
 *     { success: false, error: <backendErrorOrMessage>, status: <httpStatus|null> }
 */
export async function uploadDocuments(file, onProgress) {
  const accessToken = getAccessToken();
  const url = `${API_BASE}/uploadDocument.php`;

  const form = new FormData();
  form.append('document', file); // ✅ actual file binary under field name "document"

  try {
    const response = await withAuthRetry(() =>
      axios.post(url, form, {
        headers: {
          Authorization: `Bearer ${accessToken}`,
          // NOTE: Do NOT manually set Content-Type for FormData in the browser.
          // Axios will set the boundary correctly.
        },
        onUploadProgress: (evt) => {
          if (!onProgress) return;

          // Some browsers can report total=0/undefined; guard it
          const total = evt.total || file?.size || 0;
          if (!total) return;

          const pct = Math.min(100, Math.round((evt.loaded * 100) / total));
          onProgress(pct);
        },
      })
    );

    // Optional: keep progress pinned at 100 on success
    if (onProgress) onProgress(100);

    // ✅ Log success (requested earlier)
    console.log('✅ uploadDocuments success:', {
      status: response.status,
      data: response.data,
      filename: file?.name,
      size: file?.size,
    });

    return {
      success: true,
      data: response.data,
      status: response.status,
    };
  } catch (err) {
    // Axios error shape: err.response?.data, err.response?.status
    const status = err?.response?.status ?? null;
    const backendError = err?.response?.data;
    const message = err?.message || 'Upload failed';

    // Prefer backend error payload if present
    const error = backendError ?? message;

    console.error('uploadDocuments failure:', {
      status,
      error,
      filename: file?.name,
      size: file?.size,
    });

    return {
      success: false,
      error,
      status,
    };
  }
}
